from collections import defaultdict

class Solution(object):
    def minLength(self, nums, k):
        freq = defaultdict(int)
        distinct_sum = 0
        ans = float('inf')
        left = 0
        for right in range(len(nums)):
            v = nums[right]
            if freq[v] == 0:
                distinct_sum += v
            elif freq[v] == 1:
                distinct_sum -= v
            freq[v] += 1
            while distinct_sum >= k and left <= right:
                ans = min(ans, right - left + 1)
                lv = nums[left]
                freq[lv] -= 1
                if freq[lv] == 1:
                    distinct_sum += lv
                elif freq[lv] == 0:
                    distinct_sum -= lv
                left += 1
        return ans if ans != float('inf') else -1
